const AWS = require('aws-sdk');
const axios = require('axios');
const { DynamoDB } = require('aws-sdk');

const dynamoDB = new DynamoDB.DocumentClient();
const TABLE_NAME = process.env.TABLE_NAME;
const PAYMENT_API_URL = process.env.PAYMENT_API_URL;

exports.handler = async (event) => {
    for (const record of event.Records) {
        const order = JSON.parse(record.body);
        
        if (!validateOrder(order)) {
            console.error('Invalid order:', order);
            continue;
        }

        try {
            const paymentResponse = await processPayment(order);
            await updateOrderStatus(order.id, paymentResponse.status);
        } catch (error) {
            console.error('Error processing order:', error);
        }
    }
};

const validateOrder = (order) => {
    return order && typeof order.id === 'string' && typeof order.amount === 'number';
};

const processPayment = async (order) => {
    const response = await axios.post(PAYMENT_API_URL, {
        orderId: order.id,
        amount: order.amount,
    });
    return response.data;
};

const updateOrderStatus = async (orderId, status) => {
    const params = {
        TableName: TABLE_NAME,
        Key: { id: orderId },
        UpdateExpression: 'set #status = :status',
        ExpressionAttributeNames: {
            '#status': 'status',
        },
        ExpressionAttributeValues: {
            ':status': status,
        },
    };
    await dynamoDB.update(params).promise();
};